Reviewed and tested aac55f94938a.

I found an issue, at log.h [LogPrint_](https://github.com/bitcoin/bitcoin/pull/30343/changes#diff-c75b427ca21222164fa8e95d82f29fefa6b60044d0510fe85f4e06e57cdc154bR160) , rvalue source arguments can be bound by reference and used after their lifetime ends. I tried to solve this in a few ways, but I think the most elegant simple one is to block rvalues at compile time by deleting the overload. I failed to find any rvalue usage that exists today. Solution suggested in inline comments.

I used the following test to confirm the lifetime issue (for demo of the issue only; we don't need it if we block rvalues at compile time):


```
struct LifetimeCheckedSource : public util::log::Source {
    LifetimeCheckedSource(int& counter, BCLog::Logger& logger, bool& alive)
        : Source{BCLog::VALIDATION, &logger}, m_counter{counter}, m_alive{alive}
    {
        m_alive = true;
    }
    ~LifetimeCheckedSource()
    {
        m_alive = false;
    }
    template <typename... Args>
    std::string Format(util::ConstevalFormatString<sizeof...(Args)> fmt, const Args&... args) const
    {
        CHECK_NONFATAL(m_alive);
        return tfm::format("Custom #%d %s", ++m_counter, tfm::format(fmt, args...));
    }
    int& m_counter;
    bool& m_alive;
};

BOOST_AUTO_TEST_CASE(logging_temporary_source_lifetime)
{
    BCLog::Logger logger;
    logger.m_log_timestamps = false;
    logger.EnableCategory(BCLog::LogFlags::ALL);
    logger.SetLogLevel(BCLog::Level::Debug);
    logger.StartLogging();

    std::vector<std::string> messages;
    logger.PushBackCallback([&](const std::string& s) { messages.push_back(s); });

    int counter{0};
    bool alive{false};
    auto make_source = [&counter, &logger, &alive]() {
        return LifetimeCheckedSource{counter, logger, alive};
    };
    LogDebug(make_source(), "temporary %s", "source");

    BOOST_REQUIRE_EQUAL(messages.size(), 1U);
    BOOST_CHECK_EQUAL(messages[0], "[validation] Custom #1 temporary source\n");
    BOOST_CHECK_EQUAL(counter, 1);
}

```

Run build/bin/test_bitcoin --run_test=logging_tests/logging_temporary_source_lifetime to see it fail.

